  private readonly len: number;

  constructor(input: string) {
    this.s = input;
    this.pos = 0;
    this.len = input.length;
  }

  /** Skip JSON insignificant whitespace */
  skipWhitespace(): void {
    while (this.pos < this.len) {
      const c = this.s.charCodeAt(this.pos);
      if (
        c === 0x20 || // space
        c === 0x09 || // tab
        c === 0x0a || // newline
        c === 0x0d    // carriage return
      ) {
        this.pos++;
      } else {
        break;
      }
    }
  }

  /** Return current character without consuming */
  peek(): string | undefined {
    return this.s[this.pos];
  }

  /** Consume and return a specific expected character (optional) */
  consume(expected?: string): string {
    const ch = this.s[this.pos++];
    if (expected && ch !== expected) {
      throw new Error(`Expected '${expected}' but found '${ch}'`);
    }
    return ch;
  }

