// Helper type that turns a single "key=value" pair into an object type.
type ParsePair<P extends string> =
  P extends `${infer Key}=${infer Val}` ? Record<Key, Val> : {};

// Main type: recursively splits the query string on '&' and merges all pairs.
export type ParseQuery<S extends string> =
  S extends `${infer Head}&${infer Tail}`
    ? ParsePair<Head> & ParseQuery<Tail>
    : S extends ''
      ? {}
      : ParsePair<S>;

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private _handlers: {
    [K in keyof TEvents]?: Array<( ...args: TEvents[K]) => void>;
  } = {};

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    let handlers = this._handlers[name];
    if (!handlers) {
      const newHandlers: Array<( ...args: TEvents[K]) => void> = [];
      this._handlers[name] = newHandlers;
      handlers = newHandlers;
    }
    handlers.push(handler);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this._handlers[name];
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

export class MedianStream {
  private low: Heap<number>;   // max‑heap for the lower half
  private high: Heap<number>;  // min‑heap for the upper half

  constructor() {
    // larger numbers have higher priority in `low` → max‑heap
    this.low = new Heap<number>((a, b) => a > b);
    // smaller numbers have higher priority in `high` → min‑heap
    this.high = new Heap<number>((a, b) => a < b);
  }

  add(n: number): void {
    if (this.low.size === 0 || n <= this.low.peek()!) {
      this.low.push(n);
    } else {
      this.high.push(n);
    }
    // keep |low| >= |high| and |low| - |high| ≤ 1
    if (this.low.size > this.high.size + 1) {
      const moved = this.low.pop();
      if (moved !== undefined) this.high.push(moved);
    } else if (this.low.size < this.high.size) {
      const moved = this.high.pop();
      if (moved !== undefined) this.low.push(moved);
    }
  }

  median(): number {
    if (this.low.size === 0 && this.high.size === 0) {
      throw new Error('No elements in the stream');
    }
    const total = this.low.size + this.high.size;
    if (total % 2 === 1) {
      // odd count → middle element is top of low heap
      return this.low.peek() as number;
    } else {
      // even count → average of the two middle values
      const l = this.low.peek() as number;
      const h = this.high.peek() as number;
      return (l + h) / 2;
    }
  }
}

/** Internal binary heap implementation */
class Heap<T> {
  private data: T[] = [];
  constructor(private lessThan: (a: T, b: T) => boolean) {}

  get size(): number {
    return this.data.length;
  }

  push(item: T): void {
    this.data.push(item);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): T | undefined {
    if (this.size === 0) return undefined;
    const top = this.data[0];
    const last = this.data.pop()!;
    if (this.size > 0) {
      this.data[0] = last;
      this.bubbleDown(0);
    }
    return top;
  }

  peek(): T | undefined {
    return this.data[0];
  }

  private swap(i: number, j: number): void {
    const tmp = this.data[i];
    this.data[i] = this.data[j];
    this.data[j] = tmp;
  }

  private bubbleUp(idx: number): void {
    while (idx > 0) {
      const parent = ((idx + 1) >> 1) - 1;
      if (this.lessThan(this.data[idx], this.data[parent])) {
        this.swap(idx, parent);
        idx = parent;
      } else break;
    }
  }

  private bubbleDown(idx: number): void {
    const n = this.size;
    while (true) {
      let smallest = idx;
      const left = 2 * idx + 1;
      const right = 2 * idx + 2;
      if (left < n && this.lessThan(this.data[left], this.data[smallest])) {
        smallest = left;
      }
      if (right < n && this.lessThan(this.data[right], this.data[smallest])) {
        smallest = right;
      }
      if (smallest !== idx) {
        this.swap(idx, smallest);
        idx = smallest;
      } else break;
    }
  }
}
